// 1. Безопасно получаем данные
let payload;
if (typeof query === 'object' && query !== null) {
  payload = query;
} else {
  try {
    payload = JSON.parse(query);
  } catch (e) {
    return JSON.stringify({ success: false, error: "Не удалось распарсить JSON" });
  }
}

const chatId = Number(payload.chat_id);
const questionText = payload.question || payload.text;
const options = payload.options;
const sessionId = payload.session_id;

// 2. Форматируем массив inline-кнопок
let optionsArray = [];
if (typeof options === 'string') {
  optionsArray = options.split('|').map(item => item.trim());
} else if (Array.isArray(options)) {
  optionsArray = options;
}

// Заменяем callback_data на короткие индексы "0", "1", "2" для обхода лимита 64 байта
const inlineKeyboard = optionsArray.map((option, index) => [
  { 
    text: String(option), 
    callback_data: `${index}:${sessionId}` 
  }
]);

// 3. Отправка запроса
try {
  await new Promise(resolve => setTimeout(resolve, 800));
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot8835841549:AAEWCJARgrScdfoIq3WgI6gS8Xxayq6HCp4/sendMessage',
    body: {
      chat_id: chatId,
      text: questionText,
      reply_markup: {
        inline_keyboard: inlineKeyboard
      }
    },
    json: true
  });

  return JSON.stringify({ success: true, message: "Сообщение отправлено" });
} catch (error) {
  // Вытаскиваем точную причину из ответа сервера Telegram
  const rawDescription = error.response?.data?.description || error.message || "Unknown network error";
  return JSON.stringify({ 
    success: false, 
    error: "Telegram API Rejected Request", 
    reason: rawDescription
  });
}

