// 1. Получаем строки из Google Sheets и ID чата из триггера
const allItems = $input.all();
const chatId = $('Telegram Trigger').first().json.message.from.id;

// 2. Переворачиваем массив и берем последние 5 строк
const lastFiveItems = allItems.reverse().slice(0, 5);

// 3. Формируем массив кнопок на основе ваших колонок Title и Materialid
const buttons = lastFiveItems.map(item => {
  const title = item.json.Title || "Article without name"; 
  const materialId = item.json.Id || "unknown";

  return [
    {
      text: title,
      callback_data: materialId 
    }
  ];
});

// 4. Формируем тело запроса для Telegram
const payload = {
  chat_id: chatId,
  text: "📌 Select a material for the quiz",
  reply_markup: {
    inline_keyboard: buttons
  }
};

// 5. Отправляем запрос в Telegram
try {
  const responseData = await this.helpers.request({
    method: 'POST',
    url: 'https://api.telegram.org/bot8835841549:AAEWCJARgrScdfoIq3WgI6gS8Xxayq6HCp4/sendMessage',
    body: payload,
    json: true
  });

  // Оборачиваем ответ, гарантируя n8n, что это объект
  return [{ json: typeof responseData === 'object' ? responseData : { result: responseData } }];
} catch (error) {
  return [{ json: { error: error.message } }];
}

